from __future__ import annotations

import json
from pathlib import Path
from typing import Annotated

try:
    import yaml
except Exception:  # optional dependency if not using YAML configs
    yaml = None  # type: ignore

from typer import Option, Typer

from harbor.cli.utils import run_async
from harbor.models.job.config import JobConfig
from harbor.models.trial.config import TaskConfig

sweeps_app = Typer(
    no_args_is_help=True, context_settings={"help_option_names": ["-h", "--help"]}
)


@sweeps_app.command("run")
def run_sweeps(
    config_path: Annotated[
        Path, Option("-c", "--config", help="Job config file (json or yaml)")
    ],
    sweeps: Annotated[
        int,
        Option("--max-sweeps", help="Max number of sweeps to run"),
    ] = 3,
    trials_per_task: Annotated[
        int,
        Option("--trials-per-task", help="Trials per task per sweep"),
    ] = 2,
    add_hint: Annotated[
        str | None,
        Option("--hint", help="Optional generic hint string to pass to agent kwargs"),
    ] = None,
    hints_file: Annotated[
        Path | None,
        Option(
            "--hints-file",
            help="JSON file mapping task name -> hint string",
            show_default=False,
        ),
    ] = None,
    export_repo: Annotated[
        str | None,
        Option(
            "--export-repo",
            help="Repo to push DatasetDict with success/failure splits",
            show_default=False,
        ),
    ] = None,
    export_repo_success: Annotated[
        str | None,
        Option(
            "--export-repo-success",
            help="Repo to push ONLY successes when using --export-separate",
            show_default=False,
        ),
    ] = None,
    export_repo_failure: Annotated[
        str | None,
        Option(
            "--export-repo-failure",
            help="Repo to push ONLY failures when using --export-separate",
            show_default=False,
        ),
    ] = None,
    push: Annotated[
        bool,
        Option("--push/--no-push", help="Push exported datasets to HF Hub"),
    ] = False,
    export_splits: Annotated[
        bool,
        Option(
            "--export-splits/--export-separate",
            help="Push one repo with splits vs two separate repos",
        ),
    ] = True,
):
    """Run successive sweeps, dropping tasks with ≥1 success each sweep.

    At the end, export traces for all sweeps as a DatasetDict with 'success' and 'failure' splits
    when --export-repo is provided and --push is set.
    """
    from harbor.job import Job

    # Load base config
    if config_path.suffix == ".yaml":
        if yaml is None:
            raise ImportError("pyyaml is required to read YAML configs; install pyyaml")
        base_config = JobConfig.model_validate(yaml.safe_load(config_path.read_text()))
    elif config_path.suffix == ".json":
        base_config = JobConfig.model_validate_json(config_path.read_text())
    else:
        raise ValueError(f"Unsupported config file format: {config_path.suffix}")

    # Apply sweep-specific overrides
    base_config.n_attempts = int(trials_per_task)

    if add_hint:
        # Merge the hint into each agent's kwargs
        for ag in base_config.agents:
            ag.kwargs = {**(ag.kwargs or {}), "hint": add_hint}

    remaining_tasks: list[TaskConfig] = base_config.tasks.copy()
    job_dirs: list[Path] = []

    # Load per-task hints if provided
    hints_map: dict[str, str] = {}
    if hints_file:
        try:
            hints_map = json.loads(hints_file.read_text())
            if not isinstance(hints_map, dict):
                print("[sweeps] --hints-file must be a JSON object {task_name: hint}")
                hints_map = {}
        except (json.JSONDecodeError, OSError) as e:
            print(f"[sweeps] Failed to read hints file: {e}")
            hints_map = {}

    # Single event loop for the whole sweep. Previously each sweep iteration
    # called `run_async` and created a fresh event loop — any singletons
    # (supabase client, httpx pool) bound to the first loop were stranded
    # when it closed, causing intermittent "Event loop is closed" failures
    # in later iterations as soon as anything touched Supabase.
    async def _run_sweep_iteration(cfg: JobConfig) -> Path:
        j = await Job.create(cfg)
        await j.run()
        return j.job_dir

    async def _run_all_sweeps() -> None:
        nonlocal remaining_tasks
        for sweep_idx in range(1, sweeps + 1):
            if not remaining_tasks:
                print("[sweeps] All tasks succeeded; stopping early.")
                break

            succeeded_by_task: set[str] = set()

            if hints_map:
                # Run one job per task to inject per-task hint into agent kwargs
                print(
                    f"[sweeps] Starting sweep {sweep_idx} with per-task hints; {len(remaining_tasks)} tasks"
                )
                for task in remaining_tasks:
                    task_name = task.get_task_id().get_name()
                    cfg = base_config.model_copy(deep=True)
                    cfg.tasks = [task]
                    cfg.job_name = (
                        f"{base_config.job_name}.sweep-{sweep_idx}.{task_name}"
                    )
                    hint_val = hints_map.get(task_name)
                    if hint_val:
                        for ag in cfg.agents:
                            ag.kwargs = {**(ag.kwargs or {}), "hint": hint_val}

                    job_dir = await _run_sweep_iteration(cfg)
                    job_dirs.append(job_dir)
                    # Scan successes for this task
                    for trial_dir in job_dir.iterdir():
                        if not trial_dir.is_dir():
                            continue
                        rp = trial_dir / "result.json"
                        if not rp.exists():
                            continue
                        try:
                            data = rp.read_text()
                            obj = json.loads(data)
                            if not isinstance(obj, dict):
                                print(f"[sweeps] Ignoring non-object result in {rp}")
                                continue
                            vr = obj.get("verifier_result")
                            reward = vr.get("reward") if isinstance(vr, dict) else None
                            if reward is not None and float(reward) > 0.0:
                                succeeded_by_task.add(task_name)
                                break
                        except json.JSONDecodeError as e:
                            print(f"[sweeps] JSON parse error in {rp}: {e}")
                        except (ValueError, OSError) as e:
                            # ValueError for float() casting; OSError for file read issues
                            print(f"[sweeps] Error processing {rp}: {e}")
            else:
                # Single job across all remaining tasks
                cfg = base_config.model_copy(deep=True)
                cfg.tasks = remaining_tasks
                cfg.job_name = f"{base_config.job_name}.sweep-{sweep_idx}"
                print(
                    f"[sweeps] Starting sweep {sweep_idx} with {len(cfg.tasks)} tasks, {cfg.n_attempts} trials/task"
                )

                job_dir = await _run_sweep_iteration(cfg)
                job_dirs.append(job_dir)
                for trial_dir in job_dir.iterdir():
                    if not trial_dir.is_dir():
                        continue
                    result_path = trial_dir / "result.json"
                    if not result_path.exists():
                        continue
                    try:
                        data = result_path.read_text()
                        obj = json.loads(data)
                        if not isinstance(obj, dict):
                            print(
                                f"[sweeps] Ignoring non-object result in {result_path}"
                            )
                            continue
                        vr = obj.get("verifier_result")
                        reward = vr.get("reward") if isinstance(vr, dict) else None
                        if reward is not None and float(reward) > 0.0:
                            task_name = (
                                obj.get("task_name") or trial_dir.name.split("__", 1)[0]
                            )
                            succeeded_by_task.add(task_name)
                    except json.JSONDecodeError as e:
                        print(f"[sweeps] JSON parse error in {result_path}: {e}")
                    except (ValueError, OSError) as e:
                        print(f"[sweeps] Error processing {result_path}: {e}")

            # Filter remaining tasks for next sweep
            before = len(remaining_tasks)
            remaining_tasks = [
                t
                for t in remaining_tasks
                if t.get_task_id().get_name() not in succeeded_by_task
            ]
            print(
                f"[sweeps] Sweep {sweep_idx} complete. Tasks: {before} -> {len(remaining_tasks)} remaining"
            )

    run_async(_run_all_sweeps())

    # Export traces at the end
    # Merge all job dirs and export success/failure splits
    if push and (export_repo or (export_repo_success and export_repo_failure)):
        from datasets import Dataset, DatasetDict, concatenate_datasets

        from harbor.utils.traces_utils import export_traces as _export_traces

        print("[sweeps] Exporting success/failure splits to HF")
        # Export success split
        ds_success = None
        ds_failure = None
        for jd in job_dirs:
            ds_s = _export_traces(
                jd,
                recursive=True,
                episodes="last",
                to_sharegpt=False,
                push=False,
                verbose=False,
                success_filter="success",
            )
            ds_f = _export_traces(
                jd,
                recursive=True,
                episodes="last",
                to_sharegpt=False,
                push=False,
                verbose=False,
                success_filter="failure",
            )
            if ds_success is None:
                ds_success = ds_s
                ds_failure = ds_f
            else:
                assert isinstance(ds_success, Dataset)
                assert isinstance(ds_failure, Dataset)
                assert isinstance(ds_s, Dataset)
                assert isinstance(ds_f, Dataset)
                if len(ds_s) > 0:
                    ds_success = concatenate_datasets([ds_success, ds_s])
                if len(ds_f) > 0:
                    ds_failure = concatenate_datasets([ds_failure, ds_f])
        if ds_success is None:
            ds_success = Dataset.from_list([])
        if ds_failure is None:
            ds_failure = Dataset.from_list([])
        if export_splits:
            if not export_repo:
                raise ValueError("--export-splits requires --export-repo <org/name>")
            dd = DatasetDict({"success": ds_success, "failure": ds_failure})  # ty: ignore[no-matching-overload]
            dd.push_to_hub(export_repo)
            print(f"[sweeps] Pushed splits to {export_repo}")
        else:
            if not (export_repo_success and export_repo_failure):
                raise ValueError(
                    "--export-separate requires --export-repo-success and --export-repo-failure"
                )
            if len(ds_success) > 0:
                ds_success.push_to_hub(export_repo_success)  # ty: ignore[unresolved-attribute]
                print(f"[sweeps] Pushed successes to {export_repo_success}")
            else:
                print("[sweeps] No successes to push")
            if len(ds_failure) > 0:
                ds_failure.push_to_hub(export_repo_failure)  # ty: ignore[unresolved-attribute]
                print(f"[sweeps] Pushed failures to {export_repo_failure}")
            else:
                print("[sweeps] No failures to push")
    else:
        print("[sweeps] Skipping push; set --push and --export-repo to upload.")

import shutil
import subprocess
from pathlib import Path
from typing import Annotated

from rich.console import Console
from typer import Option, Typer

cache_app = Typer(
    no_args_is_help=True, context_settings={"help_option_names": ["-h", "--help"]}
)
console = Console()


@cache_app.command()
def clean(
    force: Annotated[
        bool,
        Option(
            "-f",
            "--force",
            help="Skip confirmation prompt and clean immediately.",
        ),
    ] = False,
    dry: Annotated[
        bool,
        Option(
            "--dry",
            help="Show what would be cleaned without actually cleaning.",
        ),
    ] = False,
    no_docker: Annotated[
        bool,
        Option(
            "--no-docker",
            help="Skip Docker image cleanup.",
        ),
    ] = False,
    no_cache_dir: Annotated[
        bool,
        Option(
            "--no-cache-dir",
            help="Skip cache directory cleanup.",
        ),
    ] = False,
):
    """Clean Harbor cache: remove Docker images (alexgshaw/*, hb__*, sb__*) and ~/.cache/harbor folder."""
    cache_dir = Path("~/.cache/harbor").expanduser()

    cache_exists = cache_dir.exists()
    cache_size = None
    if cache_exists and not no_cache_dir:
        total_size = sum(f.stat().st_size for f in cache_dir.rglob("*") if f.is_file())
        cache_size = total_size / (1024 * 1024)

    docker_images = []
    if not no_docker:
        try:
            result = subprocess.run(
                ["docker", "images", "--format", "{{.Repository}}:{{.Tag}}"],
                capture_output=True,
                text=True,
                check=True,
            )
            all_images = result.stdout.strip().split("\n")
            docker_images = [
                img
                for img in all_images
                if img.startswith("alexgshaw/")
                or img.startswith("hb__")
                or img.startswith("sb__")
            ]
        except subprocess.CalledProcessError:
            console.print("[yellow]⚠️  Could not list Docker images[/yellow]")
        except FileNotFoundError:
            console.print(
                "[yellow]⚠️  Docker not found, skipping image cleanup[/yellow]"
            )

    console.print("\n[bold]Harbor Cache Cleanup[/bold]\n")
    if dry:
        console.print("[yellow]DRY RUN - No changes will be made[/yellow]\n")

    if cache_exists and not no_cache_dir:
        console.print(f"[blue]Cache directory:[/blue] {cache_dir}")
        console.print(f"[blue]Cache size:[/blue] {cache_size:.2f} MB\n")
    elif not no_cache_dir:
        console.print(f"[dim]Cache directory not found: {cache_dir}[/dim]\n")

    if docker_images:
        console.print(
            f"[blue]Docker images to remove:[/blue] {len(docker_images)} image(s)"
        )
        for img in docker_images[:10]:
            console.print(f"  • {img}")
        if len(docker_images) > 10:
            console.print(f"  ... and {len(docker_images) - 10} more")
        console.print()
    elif not no_docker:
        console.print("[dim]No matching Docker images found[/dim]\n")

    should_clean_cache = cache_exists and not no_cache_dir
    should_clean_docker = bool(docker_images) and not no_docker

    if not should_clean_cache and not should_clean_docker:
        console.print("[green]✓ Nothing to clean[/green]")
        return

    if dry:
        console.print("[yellow]✓ Dry run completed (no changes made)[/yellow]")
        return

    if not force:
        response = console.input("[yellow]Proceed with cleanup? (y/N):[/yellow] ")
        if response.lower() not in ["y", "yes"]:
            console.print("[dim]Cleanup cancelled[/dim]")
            return

    cleaned = False

    if should_clean_cache:
        try:
            shutil.rmtree(cache_dir)
            console.print(f"[green]✓ Removed cache directory: {cache_dir}[/green]")
            cleaned = True
        except Exception as e:
            console.print(f"[red]❌ Failed to remove cache directory: {e}[/red]")

    if should_clean_docker:
        try:
            subprocess.run(
                ["docker", "rmi", "-f"] + docker_images,
                capture_output=True,
                text=True,
                check=True,
            )
            console.print(
                f"[green]✓ Removed {len(docker_images)} Docker image(s)[/green]"
            )
            cleaned = True
        except subprocess.CalledProcessError as e:
            console.print(f"[red]❌ Failed to remove Docker images: {e.stderr}[/red]")
        except FileNotFoundError:
            console.print(
                "[yellow]⚠️  Docker not found, skipping image cleanup[/yellow]"
            )

    if cleaned:
        console.print("\n[green bold]✓ Cache cleanup completed[/green bold]")
    else:
        console.print("\n[yellow]⚠️  No cleanup was performed[/yellow]")

from __future__ import annotations

from pathlib import Path
from typing import Annotated, Any
from uuid import UUID

from rich.console import Console
from typer import Option, Typer, echo

from harbor.leaderboard.report_display import (
    print_static_validation_report,
    write_static_validation_report_json,
)
from harbor.leaderboard.static_validation_report import StaticValidationReport

leaderboard_app = Typer(
    name="leaderboard",
    no_args_is_help=True,
    context_settings={"help_option_names": ["-h", "--help"]},
)

_console = Console()


def _emit_report(
    report: StaticValidationReport | dict[str, Any] | None,
    output: Path | None,
) -> None:
    if report is None:
        return
    if output is not None:
        print_static_validation_report(
            report,
            console=_console,
            show_errors=False,
            show_warnings=False,
        )
        write_static_validation_report_json(report, output)
        echo(f"Static validation report written to {output.expanduser().resolve()}")


@leaderboard_app.command(name="submit")
def submit_command(
    leaderboard: Annotated[
        str,
        Option(
            "--leaderboard",
            "-l",
            help="Target leaderboard slug (e.g. terminal-bench/terminal-bench-2-1).",
        ),
    ],
    job_id: Annotated[
        list[UUID] | None,
        Option(
            "--job-id",
            "-j",
            help="Harbor Hub job UUID to attach. Repeatable for multi-job submissions.",
        ),
    ] = None,
    submission: Annotated[
        UUID | None,
        Option(
            "--submission",
            "-s",
            help="Existing pending submission UUID to attach jobs or update metadata.",
        ),
    ] = None,
    metadata: Annotated[
        Path | None,
        Option(
            "--metadata",
            "-m",
            help=(
                "Path to metadata.yaml. Required for new submissions and for "
                "metadata-only updates; optional when attaching jobs to an "
                "existing submission (--submission)."
            ),
        ),
    ] = None,
    output: Annotated[
        Path | None,
        Option(
            "--output",
            "-o",
            help="Write the full static_validation_report JSON to this path.",
        ),
    ] = None,
    debug: Annotated[
        bool,
        Option("--debug", help="Show traceback on failure.", hidden=True),
    ] = False,
) -> None:
    """Submit uploaded job(s) to a Harbor Hub leaderboard.

    Run ``harbor upload`` first, then pass the printed job UUID with
    ``--job-id``. Documentation: https://harborframework.com/docs/leaderboard/submit
    """
    from harbor.cli.utils import run_async
    from harbor.leaderboard.submit import LeaderboardSubmitError, LeaderboardSubmitter

    job_ids = list(job_id or [])
    if submission is None and metadata is None:
        echo("Error: --metadata is required when creating a new submission")
        raise SystemExit(1)
    if submission is not None and not job_ids and metadata is None:
        echo(
            "Error: --metadata is required when updating submission metadata "
            "without --job-id"
        )
        raise SystemExit(1)

    metadata_path = metadata.expanduser().resolve() if metadata is not None else None
    output_path = output.expanduser().resolve() if output is not None else None

    async def _submit() -> None:
        submitter = LeaderboardSubmitter()
        result = await submitter.submit(
            leaderboard_slug=leaderboard,
            job_ids=job_ids,
            metadata_path=metadata_path,
            submission_id=submission,
        )
        _emit_report(result.static_validation_report, output_path)
        echo(f"Leaderboard submission: {result.submission_id}")
        echo(f"Leaderboard: {result.leaderboard_slug}")
        if result.job_ids:
            echo(f"Jobs: {', '.join(str(j) for j in result.job_ids)}")

    try:
        run_async(_submit())
    except LeaderboardSubmitError as exc:
        _emit_report(exc.static_validation_report, output_path)
        if exc.static_validation_report is None or output_path is None:
            echo(f"Error: {exc}")
        else:
            echo("Error: Static validation failed (see report above or JSON file)")
        raise SystemExit(1) from None
    except SystemExit:
        raise
    except Exception as exc:
        echo(f"Error: {type(exc).__name__}: {exc}")
        if debug:
            raise
        raise SystemExit(1) from None

import sys
from typing import Annotated

from typer import Exit, Option, Typer, echo

from harbor.auth.errors import AuthenticationError
from harbor.cli.utils import run_async
from harbor.constants import HARBOR_REGISTRY_WEBSITE_URL

auth_app = Typer(no_args_is_help=True)


@auth_app.command()
def login(
    no_browser: Annotated[
        bool,
        Option(
            "--no-browser",
            help="Do not open a browser. Displays a URL to open on any device; "
            "after signing in, paste the authorization code shown on the page.",
        ),
    ] = False,
    callback_url: Annotated[
        str | None,
        Option(
            "--callback-url",
            help="Paste the full OAuth callback URL after completing sign-in.",
        ),
    ] = None,
) -> None:
    """Authenticate with Harbor via GitHub OAuth."""

    async def _login():
        from harbor.auth.handler import get_auth_handler

        handler = await get_auth_handler()
        is_interactive = sys.stdin.isatty() and sys.stdout.isatty()
        try:
            user_id = await handler.login(
                callback_url=callback_url,
                open_browser=not no_browser,
                allow_manual=is_interactive and callback_url is None,
            )
        except AuthenticationError as exc:
            echo(f"Login failed: {exc}")
            raise Exit(1)
        echo(f"Logged in as {user_id}")
        echo(f"Visit {HARBOR_REGISTRY_WEBSITE_URL}/profile to create and manage orgs.")

    run_async(_login())


@auth_app.command()
def logout() -> None:
    """Sign out and clear stored credentials."""

    async def _logout():
        from harbor.auth.handler import get_auth_handler

        handler = await get_auth_handler()
        await handler.logout()
        echo("Logged out")

    run_async(_logout())


@auth_app.command()
def status() -> None:
    """Show current authentication status."""

    async def _status():
        from harbor.auth.handler import get_auth_handler

        handler = await get_auth_handler()
        if not await handler.is_authenticated():
            echo("Not authenticated. Run `harbor auth login`.")
            return

        username = await handler.get_github_username()
        if username is None:
            if await handler.is_authenticated():
                echo("Logged in as unknown user")
            else:
                echo("Not authenticated. Run `harbor auth login`.")
            return

        echo(f"Logged in as {username}")

    run_async(_status())

from rich.console import Console
from rich.table import Table
from typer import Typer

from harbor.cli.plugin_registry import (
    PLUGIN_ENTRY_POINT_GROUP,
    list_plugin_entry_points,
)

plugins_app = Typer(
    no_args_is_help=True, context_settings={"help_option_names": ["-h", "--help"]}
)
console = Console()


@plugins_app.command("list")
def list_plugins() -> None:
    """List installed Harbor plugins registered via entry points."""
    registered = list_plugin_entry_points()
    if not registered:
        console.print("No Harbor plugins installed.")
        console.print(
            "Plugins register under the "
            f"[bold]{PLUGIN_ENTRY_POINT_GROUP}[/bold] entry point group."
        )
        return

    table = Table(title="Harbor Plugins")
    table.add_column("Name")
    table.add_column("Import path")
    for name in sorted(registered):
        table.add_row(name, registered[name])
    console.print(table)

import json
import tomllib
from enum import Enum
from pathlib import Path

import yaml
from pydantic import BaseModel, Field


class CheckOutcome(str, Enum):
    PASS = "pass"
    FAIL = "fail"
    NOT_APPLICABLE = "not_applicable"


class QualityCheckModel(BaseModel):
    explanation: str
    outcome: CheckOutcome


class RubricCriterion(BaseModel):
    name: str
    description: str
    guidance: str


class Rubric(BaseModel):
    criteria: list[RubricCriterion]


class QualityCheckResult(BaseModel):
    checks: dict[str, QualityCheckModel] = Field(default_factory=dict)
    cost_usd: float | None = None
    task_name: str | None = None
    error: str | None = None


class CheckReport(BaseModel):
    """Result of checking one or more tasks (one QualityCheckResult per task)."""

    results: list[QualityCheckResult]

    @property
    def total_cost_usd(self) -> float | None:
        costs = [r.cost_usd for r in self.results if r.cost_usd is not None]
        return sum(costs) if costs else None


DEFAULT_RUBRIC_PATH = Path(__file__).parent / "default_rubric.toml"


def load_rubric(path: Path | None = None) -> Rubric:
    """Load a rubric from a TOML, YAML, or JSON file. Uses the default rubric if no path is given."""
    rubric_path = path if path is not None else DEFAULT_RUBRIC_PATH
    text = rubric_path.read_text()
    suffix = rubric_path.suffix.lower()

    if suffix == ".toml":
        data = tomllib.loads(text)
    elif suffix in (".yaml", ".yml"):
        data = yaml.safe_load(text)
    elif suffix == ".json":
        data = json.loads(text)
    else:
        raise ValueError(
            f"Unsupported rubric format '{suffix}'. Use .toml, .yaml, .yml, or .json."
        )

    return Rubric.model_validate(data)

"""Package configuration models for Harbor task packages.

This module provides PackageReference for specifying package versions.
PackageInfo is now defined in harbor.models.task.config and can be used
as an optional field in TaskConfig for backward compatibility.
"""

from typing import override
import re

from pydantic import BaseModel, Field, field_validator

from harbor.constants import ORG_NAME_PATTERN

from harbor.models.package.version_ref import VersionRef

__all__ = [
    "PackageReference",
]


class PackageReference(BaseModel):
    """A reference to a specific package version.

    Used in dataset manifests and CLI commands to specify package versions.
    The ref field accepts tags, revision numbers, or content hash digests.
    """

    name: str = Field(
        ...,
        description="Package name in org/name format",
    )
    ref: str = Field(
        default="latest",
        description="Version reference (tag, revision number, or digest)",
    )

    @field_validator("name")
    @classmethod
    def validate_name_format(cls, v: str) -> str:
        """Validate that name follows org/name format."""
        if not re.match(ORG_NAME_PATTERN, v) or ".." in v:
            raise ValueError(
                f"Package name must be in 'org/name' format with alphanumeric characters, "
                f"hyphens, underscores, and dots. Cannot start with a dot or contain '..'. Got: {v}"
            )
        return v

    @property
    def parsed_ref(self) -> VersionRef:
        """Parse the ref string into a VersionRef."""
        return VersionRef.parse(self.ref)

    @classmethod
    def parse(cls, ref_string: str) -> "PackageReference":
        """Parse a package reference string like 'org/name@ref'.

        Args:
            ref_string: Package reference in 'org/name@ref' format.
                If no '@' is present, defaults to 'latest'.

        Returns:
            PackageReference instance

        Raises:
            ValueError: If the format is invalid
        """
        if "@" not in ref_string:
            return cls(name=ref_string, ref="latest")

        name, ref = ref_string.rsplit("@", 1)
        return cls(name=name, ref=ref)

    @override
    def __str__(self) -> str:
        return f"{self.name}@{self.ref}"

    @override
    def __hash__(self) -> int:
        return hash((self.name, self.ref))

    @override
    def __eq__(self, other: object) -> bool:
        if not isinstance(other, PackageReference):
            return NotImplemented
        return self.name == other.name and self.ref == other.ref

    @property
    def org(self) -> str:
        """Extract organization from package name."""
        return self.name.split("/")[0]

    @property
    def short_name(self) -> str:
        """Extract short name (without org) from package name."""
        return self.name.split("/")[1]
